def binary_search(arr, target):
    left, right = 0, len(arr) - 1  # Initialize right to the last index
    while left <= right:
        mid = (left + right) // 2
        if arr[mid] == target:
            return mid
        elif arr[mid] < target:
            left = mid + 1  # Target is in the right half
        else:
            right = mid - 1 # Target is in the left half
    return -1

